import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    next_node = None
    min_product = np.inf

    for node in unvisited_nodes:
        if node not in truck_nodes:
            total_distance_left = distance_matrix[current_node, node] + distance_matrix[node, depot_node] + np.sum(distance_matrix[node, unvisited_nodes])
            distance_current_next = distance_matrix[current_node, node]
            product = distance_current_next * total_distance_left

            if product < min_product:
                next_node = node
                min_product = product

    return next_node
